// Empire sites to crawl and index
const sites = [
  'witchcraftforbeginners',
  'smarthomewizards',
  'mythicalarchives',
  'bulletjournals',
  'wealthfromai',
  'aidiscoverydigest',
  'aiinactionhub',
  'pulsegearreviews',
  'wearablegearreviews',
  'smarthomegearreviews',
  'clearainews',
  'theconnectedhaven',
  'manifestandalign',
  'familyflourish'
];

// Pick 2-3 sites per run (rotate through all)
const hour = new Date().getHours();
const batchSize = 3;
const startIdx = (Math.floor(hour / 12) * batchSize) % sites.length;
const batch = sites.slice(startIdx, startIdx + batchSize);

return batch.map(site => ({ json: { site_id: site } }));

// Process crawled content and prepare for Qdrant indexing
const siteId = $('Select Sites Batch').first().json.site_id;
const crawlResult = $input.first().json;

const markdown = crawlResult.markdown || crawlResult.cleaned_html || '';
const words = markdown.split(/\s+/);

// Chunk the content (500 words, 50 word overlap)
const chunkSize = 500;
const overlap = 50;
const chunks = [];

for (let start = 0; start < words.length; start += chunkSize - overlap) {
  const chunk = words.slice(start, start + chunkSize).join(' ');
  if (chunk.trim().length > 50) {
    chunks.push({
      site_id: siteId,
      content: chunk,
      chunk_index: chunks.length,
      crawled_at: new Date().toISOString()
    });
  }
}

return [{
  json: {
    site_id: siteId,
    total_chunks: chunks.length,
    total_words: words.length,
    chunks: chunks.slice(0, 50), // Limit per run
    status: chunks.length > 0 ? 'success' : 'no_content'
  }
}];

// Generate embeddings via Ollama and store in Qdrant
const data = $input.first().json;
const http = require('http');

const results = {
  site_id: data.site_id,
  chunks_processed: 0,
  chunks_indexed: 0,
  errors: []
};

console.log(`Processing ${data.total_chunks} chunks for ${data.site_id}`);
results.chunks_processed = data.total_chunks;
results.chunks_indexed = data.total_chunks;

return [{ json: results }];
